## Task 31: Mobile App — Profile Screen + Settings

### Modify `apps/mobile/app/(tabs)/profile.tsx`

Read the existing file first. Replace the placeholder with a full profile screen showing:

- User avatar (first letter of name as a circle), name, email
- Push notification preferences toggle (using Switch component)
- Language selector (dropdown or buttons for en/fr/es/ar) that changes i18n language
- Link to referral screen (using `router.push('/referral')`)
- Transaction history list (fetched from transactions table via customer_cards)
- Sign out button

Use `useAuthStore` for session/profile, `useTranslation` for i18n, and `useAuth` for signOut.

```tsx
import { useEffect, useState } from 'react';
import { View, Text, ScrollView, TouchableOpacity, Switch, StyleSheet, FlatList } from 'react-native';
import { useRouter } from 'expo-router';
import { useTranslation } from 'react-i18next';
import { useAuthStore } from '../../lib/store';
import { useAuth } from '../../hooks/useAuth';
import { supabase } from '../../lib/supabase';
import i18n from '../../lib/i18n';

const LANGUAGES = [
  { code: 'en', label: 'English' },
  { code: 'fr', label: 'Français' },
  { code: 'es', label: 'Español' },
  { code: 'ar', label: 'العربية' },
];

export default function ProfileScreen() {
  const { t } = useTranslation();
  const router = useRouter();
  const session = useAuthStore((s) => s.session);
  const profile = useAuthStore((s) => s.profile);
  const { signOut } = useAuth();
  const [pushEnabled, setPushEnabled] = useState(true);
  const [transactions, setTransactions] = useState<any[]>([]);
  const [currentLang, setCurrentLang] = useState(i18n.language);

  useEffect(() => {
    if (session) fetchTransactions();
  }, [session]);

  async function fetchTransactions() {
    const { data: cards } = await supabase
      .from('customer_cards')
      .select('id')
      .eq('customer_id', session!.user.id);

    if (!cards || cards.length === 0) return;
    const cardIds = cards.map(c => c.id);

    const { data } = await supabase
      .from('transactions')
      .select('*')
      .in('card_id', cardIds)
      .order('created_at', { ascending: false })
      .limit(20);

    if (data) setTransactions(data);
  }

  function changeLanguage(code: string) {
    i18n.changeLanguage(code);
    setCurrentLang(code);
  }

  const initials = (profile?.name || session?.user.email || '?')[0].toUpperCase();

  return (
    <ScrollView style={styles.container}>
      {/* Avatar */}
      <View style={styles.avatarSection}>
        <View style={styles.avatar}>
          <Text style={styles.avatarText}>{initials}</Text>
        </View>
        <Text style={styles.name}>{profile?.name || 'User'}</Text>
        <Text style={styles.email}>{session?.user.email}</Text>
      </View>

      {/* Push Notifications */}
      <View style={styles.row}>
        <Text style={styles.rowLabel}>{t('profile.notifications')}</Text>
        <Switch value={pushEnabled} onValueChange={setPushEnabled} />
      </View>

      {/* Language */}
      <Text style={styles.sectionTitle}>{t('profile.language')}</Text>
      <View style={styles.langRow}>
        {LANGUAGES.map(lang => (
          <TouchableOpacity
            key={lang.code}
            style={[styles.langBtn, currentLang === lang.code && styles.langBtnActive]}
            onPress={() => changeLanguage(lang.code)}
          >
            <Text style={[styles.langBtnText, currentLang === lang.code && styles.langBtnTextActive]}>{lang.label}</Text>
          </TouchableOpacity>
        ))}
      </View>

      {/* Referral */}
      <TouchableOpacity style={styles.menuItem} onPress={() => router.push('/referral')}>
        <Text style={styles.menuItemText}>{t('profile.referral')}</Text>
        <Text style={styles.arrow}>→</Text>
      </TouchableOpacity>

      {/* Transaction History */}
      <Text style={styles.sectionTitle}>Transaction History</Text>
      {transactions.length === 0 ? (
        <Text style={styles.empty}>No transactions yet</Text>
      ) : (
        transactions.map(tx => (
          <View key={tx.id} style={styles.txItem}>
            <Text style={styles.txType}>{tx.type.replace('_', ' ')}</Text>
            <View style={styles.txRight}>
              <Text style={styles.txValue}>{tx.type.includes('redeem') ? '-' : '+'}{tx.value}</Text>
              <Text style={styles.txDate}>{new Date(tx.created_at).toLocaleDateString()}</Text>
            </View>
          </View>
        ))
      )}

      {/* Sign Out */}
      <TouchableOpacity style={styles.signOutBtn} onPress={signOut}>
        <Text style={styles.signOutText}>{t('profile.signOut')}</Text>
      </TouchableOpacity>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: '#fff', padding: 20 },
  avatarSection: { alignItems: 'center', marginBottom: 24 },
  avatar: { width: 72, height: 72, borderRadius: 36, backgroundColor: '#6366f1', justifyContent: 'center', alignItems: 'center', marginBottom: 8 },
